mapper.insert:
INSERT INTO user_test_result (chapter_id, user_seq, tested_at)
VALUES
    (#{chapterId}
    ,#{userSeq}
    ,CURRENT_TIMESTAMP)

mapper.update:
UPDATE USER_QUESTION_RESULT
SET FINISHED_AT =CURRENT_TIMESTAMP
WHERE USER_SEQ = #{userSeq}
AND LESSON_ID = #{lessonId}

UPDATE USER_TEST_RESULT
SET SCORE     = #{score}
  , IS_PASS   = #{isPass}
  , TESTED_AT = CURRENT_TIMESTAMP
WHERE USER_SEQ = #{userSeq}
  AND CHAPTER_ID = #{chapterId}

mapper.select:
SELECT OPTIONS
FROM LEARNING_QUESTION
WHERE LESSON_ID = #{lessonId}
AND question_id = #{questionId}

SELECT COUNT(LESSON_ID)
FROM USER_QUESTION_RESULT
WHERE USER_SEQ = #{userSeq}
AND LESSON_ID = #{lessonId}

SELECT *
FROM LEARNING_QUESTION
       LEFT OUTER JOIN LEARNING_LESSON ON LEARNING_QUESTION.LESSON_ID = LEARNING_LESSON.LESSON_ID
       LEFT OUTER JOIN LEARNING_CHAPTER ON LEARNING_LESSON.CHAPTER_ID = LEARNING_CHAPTER.CHAPTER_ID
WHERE LEARNING_LESSON.CHAPTER_ID = #{chapterId}
  AND SUBSTRING(QUESTION_ID, 21) != '1';

SELECT COUNT(*)
FROM USER_TEST_RESULT
WHERE USER_SEQ = #{userSeq}
AND CHAPTER_ID = #{chapterId}
